import React, { useEffect, useState } from "react";
import { DndProvider } from "react-dnd";
import { HTML5Backend } from "react-dnd-html5-backend";
import DraggableItem from "./DraggableItem";
import DropBox from "./DropBox";
import { startTracking, getData } from "./tracker";
import axios from "axios";

function AnimalGame({ onNext }) {
  const ANIMALS = [
    { name: "dog", emoji: "🐶", label: "Dog 🐕" },
    { name: "cat", emoji: "🐱", label: "Cat 🐈" },
    { name: "elephant", emoji: "🐘", label: "Elephant 🐘" },
    { name: "parrot", emoji: "🦜", label: "Parrot 🦜" },
    { name: "lion", emoji: "🦁", label: "Lion 🦁" },
    { name: "monkey", emoji: "🐵", label: "Monkey 🐵" },
    { name: "bear", emoji: "🐻", label: "Bear 🐻" },
    { name: "rabbit", emoji: "🐰", label: "Rabbit 🐰" },
    { name: "tiger", emoji: "🐯", label: "Tiger 🐯" },
    { name: "giraffe", emoji: "🦒", label: "Giraffe 🦒" },
  ];

  const [matches, setMatches] = useState({});
  const [showSuccess, setShowSuccess] = useState(false);

  useEffect(() => {
    startTracking();
  }, []);

  const handleDrop = (animalName) => {
    setMatches((prev) => ({
      ...prev,
      [animalName]: true,
    }));
  };

  const checkAllMatched = () => {
    return ANIMALS.every((animal) => matches[animal.name]);
  };

  const finishGame = async () => {
    if (!checkAllMatched()) {
      alert("Please match all animals first! 🐾");
      return;
    }

    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        studentId: "child_01",
        activity: "animal_drag_game",
        ...data,
      });
    } catch (err) {
      console.error("AnimalGame save failed:", err);
      alert("Progress could not be saved to the server. Continuing anyway.");
    }

    if (onNext) onNext();
  };

  const allMatched = checkAllMatched();

  if (allMatched && !showSuccess) {
    setShowSuccess(true);
  }

  return (
    <DndProvider backend={HTML5Backend}>
      <div style={{ textAlign: "center", background: "#E0FFFF", minHeight: "100vh", padding: "20px" }}>
        <h1>Match Animals 🐾</h1>

        {showSuccess && (
          <div
            style={{
              fontSize: "32px",
              fontWeight: "bold",
              color: "#FF6B9D",
              margin: "30px 0",
              padding: "20px",
              backgroundColor: "#FFE0EC",
              borderRadius: "15px",
              border: "3px solid #FF6B9D",
              animation: "pulse 1s infinite",
            }}
          >
            🎉 Perfect Kiddie You have been done perfect job 🎉
          </div>
        )}

        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", gap: "15px", margin: "20px 0" }}>
          {ANIMALS.map((animal) => (
            <DraggableItem key={animal.name} name={animal.name} emoji={animal.emoji} />
          ))}
        </div>

        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", gap: "15px", margin: "20px 0" }}>
          {ANIMALS.map((animal) => (
            <DropBox
              key={animal.name}
              acceptName={animal.name}
              label={animal.label}
              isMatched={matches[animal.name]}
              onDrop={() => handleDrop(animal.name)}
            />
          ))}
        </div>

        <button
          onClick={finishGame}
          disabled={!allMatched}
          style={{
            fontSize: "20px",
            padding: "15px 30px",
            backgroundColor: allMatched ? "#4CAF50" : "#CCCCCC",
            color: "white",
            border: "none",
            borderRadius: "10px",
            cursor: allMatched ? "pointer" : "not-allowed",
            marginTop: "20px",
            fontWeight: "bold",
          }}
        >
          {allMatched ? "Next ➡️" : "Match all animals first! 🐾"}
        </button>

        <style>{`
          @keyframes pulse {
            0%, 100% { transform: scale(1); }
            50% { transform: scale(1.05); }
          }
        `}</style>
      </div>
    </DndProvider>
  );
}

export default AnimalGame;
